@Finset.sum_range_zero : ∀ {M : Type u_1} [inst : AddCommMonoid M] (f : ℕ → M), ∑ k ∈ Finset.range 0, f k = 0
@Finset.prod_range_zero : ∀ {M : Type u_1} [inst : CommMonoid M] (f : ℕ → M), ∏ k ∈ Finset.range 0, f k = 1
@Finset.prod_range_succ : ∀ {M : Type u_1} [inst : CommMonoid M] (f : ℕ → M) (n : ℕ),
  ∏ x ∈ Finset.range (n + 1), f x = (∏ x ∈ Finset.range n, f x) * f n
Nat.factorial_zero : Nat.factorial 0 = 1
Nat.factorial_succ : ∀ (n : ℕ), (n + 1).factorial = (n + 1) * n.factorial
@mul_add : ∀ {R : Type u_1} [inst : Mul R] [inst_1 : Add R] [LeftDistribClass R] (a b c : R),
  a * (b + c) = a * b + a * c

